# ==================== Token Utilities ====================

def hash_token(token):
    """Hash a token using SHA-256 for secure storage."""
    return hashlib.sha256(token.encode('utf-8')).hexdigest()


def generate_token():
    """Generate a cryptographically secure random token."""
    return secrets.token_urlsafe(48)


def validate_access_token(token_string):
    """
    Validate an access token by checking if it exists in the database,
    is not revoked, and has not expired.

    Returns the AccessToken object if valid, None otherwise.
    """
    if not token_string:
        return None

    token_hashed = hash_token(token_string)
    token_record = AccessToken.query.filter_by(token_hash=token_hashed).first()

    if token_record is None:
        return None

    if not token_record.is_valid:
        return None

    return token_record


def extract_token_from_request():
    """
    Extract the Bearer token from the Authorization header.
    Also supports token in query parameter 'access_token' as fallback.
    """
    auth_header = request.headers.get('Authorization', '')

    if auth_header.startswith('Bearer '):
        return auth_header[7:].strip()

    # Fallback: check query parameter
    token = request.args.get('access_token')
    if token:
        return token.strip()

    # Fallback: check form data
    token = request.form.get('access_token')
    if token:
        return token.strip()

    return None


# ==================== Decorator ====================

def require_oauth(f):
    """
    Decorator to protect API endpoints by requiring a valid OAuth 2.0 access token.
    No scope validation is performed — any valid token grants access.
    Sets g.current_token and g.current_user_id for use in the endpoint.
    """
    @functools.wraps(f)
    def decorated_function(*args, **kwargs):
        token_string = extract_token_from_request()

        if not token_string:
            return jsonify({
                'error': 'missing_token',
                'error_description': 'Access token is required. Provide it via Authorization: Bearer <token> header.'
            }), 401

        token_record = validate_access_token(token_string)

        if token_record is None:
            return jsonify({
                'error': 'invalid_token',
                'error_description': 'The access token is invalid, expired, or has been revoked.'
            }), 401

        # Store token info in Flask's g object for use in the endpoint
        g.current_token = token_record
        g.current_user_id = token_record.user_id
        g.current_client = token_record.client

        return f(*args, **kwargs)

    return decorated_function


