@app.route('/api/v1/token/introspect', methods=['POST'])
@require_oauth
def introspect_token():
    """
    Protected endpoint: introspect a given token.
    The caller must itself be authenticated with a valid token.
    """
    token_to_introspect = request.form.get('token') or request.json.get('token', '') if request.is_json else request.form.get('token')

    if not token_to_introspect:
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'The "token" parameter is required.'
        }), 400

    token_record = validate_access_token(token_to_introspect)

    if token_record is None:
        return jsonify({'active': False}), 200

    return jsonify({
        'active': True,
        'client_id': token_record.client.client_id,
        'user_id': token_record.user_id,
        'token_type': 'Bearer',
        'exp': int(token_record.expires_at.replace(tzinfo=timezone.utc).timestamp()),
        'iat': int(token_record.issued_at.replace(tzinfo=timezone.utc).timestamp()),
    }), 200


@app.route('/api/v1/token/revoke', methods=['POST'])
@require_oauth
def revoke_token():
    """
    Protected endpoint: revoke a given token.
    The caller must be authenticated and can only revoke tokens belonging to the same client.
    """
    if request.is_json:
        token_to_revoke = request.json.get('token', '')
    else:
        token_to_revoke = request.form.get('token', '')

    if not token_to_revoke:
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'The "token" parameter is required.'
        }), 400

    token_hashed = hash_token(token_to_revoke)
    token_record = AccessToken.query.filter_by(token_hash=token_hashed).first()

    if token_record is None:
        # Per RFC 7009, return 200 even if token doesn't exist
        return jsonify({'status': 'ok'}), 200

    # Only allow revoking tokens belonging to the same client
    if token_record.client_id != g.current_token.client_id:
        return jsonify({
            'error': 'unauthorized',
            'error_description': 'You can only revoke tokens belonging to your client.'
        }), 403

    token_record.is_revoked = True
    db.session.commit()

    return jsonify({'status': 'revoked'}), 200


