@app.route('/admin/tokens', methods=['POST'])
def issue_token():
    """
    Admin endpoint to issue a new access token for a client.
    """
    admin_key = request.headers.get('X-Admin-Key', '')
    expected_key = os.environ.get('ADMIN_KEY', 'dev-admin-key')

    if admin_key != expected_key:
        return jsonify({
            'error': 'unauthorized',
            'error_description': 'Invalid admin key.'
        }), 403

    data = request.get_json()
    if not data or 'client_id' not in data:
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'client_id is required.'
        }), 400

    client = OAuthClient.query.filter_by(client_id=data['client_id']).first()
    if not client:
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Client not found.'
        }), 404

    if not client.is_active:
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Client is inactive.'
        }), 403

    expires_in = data.get('expires_in', 3600)
    user_id = data.get('user_id')

    raw_token = generate_token()
    token_record = AccessToken(
        token_hash=hash_token(raw_token),
        client_id=client.id,
        user_id=user_id,
        issued_at=datetime.now(timezone.utc),
        expires_at=datetime.now(timezone.utc) + timedelta(seconds=expires_in),
        is_revoked=False
    )
    db.session.add(token_record)
    db.session.commit()

    return jsonify({
        'access_token': raw_token,
        'token_type': 'Bearer',
        'expires_in': expires_in,
        'client_id': client.client_id,
        'user_id': user_id,
        'note': 'Store this token securely. It will not be shown again.'
    }), 201


